159	struct list *array_to_list(int *a, int n)
160	/*@ Require 0 <= n && n < INT_MAX && IntArray::full_shape(a, n)
161	    Ensure listrep(__return) * IntArray::full_shape(a, n)
162	*/
163	{
164	  struct list *head = malloc_list(0);
165	  struct list *tail = head;
166	  int i;
167	  /*@ Inv Assert
168	      exists v, 
169	      0 <= i && i <= n@pre && head != 0 && tail != 0 && 
170	      a == a@pre && n == n@pre && 0 <= n@pre && n@pre < INT_MAX &&
171	      store(&(tail -> data), v) *
172	      store(&(tail -> next), 0) *
173	      lseg(head, tail) *
174	      IntArray::full_shape(a, n)
175	  */
176	  for (i = 0; i < n; ++i) {
177	    struct list *node = malloc_list(a[i]);
178	    tail->next = node;
179	    tail = node;
180	  }
181	  return head;
182	}

