  7	int arr_sum(int n, int *a)
  8	/*@ With l
  9	    Require 0 < n && n < 100 && IntArray::full(a, n, l) && (forall (i: Z), (0 <= i && i < n) => (0 <= l[i] && l[i] < 100))
 10	    Ensure  __return == sum(l) && IntArray::full(a, n, l) 
 11	*/
 12	{
 13	  int i;
 14	  i = 0;
 15	  int ret;
 16	  ret = 0;
 17	    /*@ Inv Assert
 18	      0 < n@pre && n@pre < 100 && a == a@pre && n == n@pre &&
 19	      0 <= i && i <= n &&
 20	      (forall (i: Z), (0 <= i && i < n) => (0 <= l[i] && l[i] < 100)) &&
 21	      ret == sum(sublist(0, i, l)) &&
 22	      IntArray::full(a, n, l)
 23	    */
 24	  while (i < n) {
 25	    ret += a[i];
 26	    ++i;
 27	  }
 28	  return ret;
 29	}
