118	/*@ With l
119	    Require 0 < n && n < 100 && IntArray::full(a, n, l) && (forall (i: Z), (0 <= i && i < n) => (0 <= l[i] && l[i] < 100))
120	    Ensure  __return == sum(l) && IntArray::full(a, n, l)
121	*/
122	{
123	  int i = 0;
124	  int ret = 0;
125	  int *endp = a + n;
126	  /*@ Inv Assert
127	      0 < n@pre && n@pre < 100 && a == a@pre && n == n@pre &&
128	      0 <= i && i <= n@pre &&
129	      (forall (i: Z), (0 <= i && i < n) => (0 <= l[i] && l[i] < 100)) &&
130	      n@pre == Zlength(l) && endp == a + n * sizeof(int) &&
131	      ret == sum(sublist(0, i, l)) && IntArray::full(a, n@pre, l) */
132	  while (endp - (a + i) != 0) {
133	    /*@ Assert
134	      0 < n@pre && n@pre < 100 && a == a@pre && n == n@pre &&
135	      0 <= i && i < n@pre && endp != a + i * sizeof(int) &&
